// The debounce function limits the rate at which a function can fire.
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Example usage:
function logInput(value) {
  console.log("Input value:", value);
}

const debouncedLogInput = debounce(logInput, 300); // Debounce the logInput function with a 300ms delay

const inputElement = document.createElement('input');
document.body.appendChild(inputElement);

inputElement.addEventListener("input", (event) => {
  debouncedLogInput(event.target.value);
});

// Now, typing quickly in the input field will only log the value after a 300ms pause.
